// QuBins landing page: catalog + URL generators.
//
// Loads versions.json (generated by build-pages-data.py at deploy time),
// renders the image catalog table, populates the filter controls and
// generator image dropdowns, and wires up the two URL generators.
//
// No build step. Plain ES2020. Keep dependencies at zero.

(() => {
  "use strict";

  // Canonical owner/repo. mybinder normalises to lowercase server-side
  // (we hit that subtlety in the warmup workflow). The case here is
  // mostly cosmetic; we keep it matching the GitHub org name as shown.
  const REPO = "QuBins/qiskit-images";
  const PAGES = "https://qubins.org";

  // ---------------------------------------------------------------- data load
  fetch("versions.json")
    .then((r) => {
      if (!r.ok) throw new Error(`versions.json: HTTP ${r.status}`);
      return r.json();
    })
    .then(init)
    .catch((err) => {
      console.error(err);
      document.querySelector("#catalog-table tbody").innerHTML =
        `<tr><td colspan="4">Failed to load versions.json: ${err.message}</td></tr>`;
    });

  // -------------------------------------------------------------------- init
  function init(data) {
    const images = data.images;
    const latest = data.latest_qiskit;

    renderQuickStart(latest);
    renderCatalog(images);
    populateFilters(images);
    populateGeneratorImages(images, latest);
    wireGenerators(images);
  }

  // ------------------------------------------------------------- quick start
  function renderQuickStart(latest) {
    document.getElementById("qs-latest").textContent = latest;
    const tagEl = document.getElementById("qs-latest-tag");
    if (tagEl) tagEl.textContent = `latest-xl (= ${latest}-xl)`;
    document.getElementById("qs-binder-xl").href =
      `https://mybinder.org/v2/gh/${REPO}/latest-xl`;
    document.getElementById("qs-docker-copy").addEventListener("click", (e) =>
      copyToClipboard(document.getElementById("qs-docker").textContent, e.currentTarget));
  }

  // ------------------------------------------------------------ catalog table
  function renderCatalog(images) {
    const tbody = document.querySelector("#catalog-table tbody");
    const notesUl = document.getElementById("catalog-notes");
    tbody.innerHTML = "";
    notesUl.innerHTML = "";
    const seenNotes = new Map(); // note text -> footnote index

    for (const img of images) {
      const tr = document.createElement("tr");
      tr.dataset.minor = img.qiskit_minor;
      tr.dataset.flavor = img.flavor;
      if (img.is_latest) tr.classList.add("row-latest");

      const minorCell = document.createElement("td");
      minorCell.textContent = img.qiskit_minor;
      if (img.is_latest) {
        const tag = document.createElement("span");
        tag.className = "tag";
        tag.textContent = "latest";
        minorCell.appendChild(tag);
      }
      tr.appendChild(minorCell);

      const flavorCell = document.createElement("td");
      let flavorText = img.flavor;
      if (img.notes) {
        let idx = seenNotes.get(img.notes);
        if (idx === undefined) {
          idx = seenNotes.size + 1;
          seenNotes.set(img.notes, idx);
        }
        const sup = document.createElement("sup");
        sup.textContent = `[${idx}]`;
        flavorCell.append(flavorText, sup);
      } else {
        flavorCell.textContent = flavorText;
      }
      tr.appendChild(flavorCell);

      // QuBins-branded launch badge → /launch/?... redirector,
      // matching the README catalog rows (PR #42) so all of our
      // surfaces point at the same badge + redirector pair.
      const binderCell = document.createElement("td");
      const binderLink = document.createElement("a");
      binderLink.href = `${PAGES}/launch/?image=${encodeURIComponent(img.binder_tag)}`;
      binderLink.target = "_blank";
      binderLink.rel = "noopener";
      const binderImg = document.createElement("img");
      binderImg.src = `${PAGES}/badges/launch-qubins-${img.binder_tag}.svg`;
      binderImg.alt = `launch QuBins ${img.binder_tag}`;
      binderLink.appendChild(binderImg);
      binderCell.appendChild(binderLink);
      tr.appendChild(binderCell);

      const dockerCell = document.createElement("td");
      const code = document.createElement("code");
      code.textContent = `docker run --rm -p 8888:8888 ${img.docker_tag}`;
      dockerCell.appendChild(code);
      const copyBtn = document.createElement("button");
      copyBtn.className = "button secondary";
      copyBtn.style.marginLeft = "0.4rem";
      copyBtn.textContent = "Copy";
      copyBtn.addEventListener("click", () =>
        copyToClipboard(code.textContent, copyBtn));
      dockerCell.appendChild(copyBtn);
      tr.appendChild(dockerCell);

      tbody.appendChild(tr);
    }

    for (const [text, idx] of seenNotes) {
      const li = document.createElement("li");
      li.textContent = `[${idx}] ${text}`;
      notesUl.appendChild(li);
    }
  }

  // ---------------------------------------------------------------- filters
  function populateFilters(images) {
    const minorSel = document.getElementById("filter-minor");
    const seenMinors = new Set();
    for (const img of images) {
      if (seenMinors.has(img.qiskit_minor)) continue;
      seenMinors.add(img.qiskit_minor);
      const opt = document.createElement("option");
      opt.value = img.qiskit_minor;
      opt.textContent = img.qiskit_minor;
      minorSel.appendChild(opt);
    }
    minorSel.addEventListener("change", applyFilters);
    document.getElementById("filter-flavor").addEventListener("change", applyFilters);
  }

  function applyFilters() {
    const minor = document.getElementById("filter-minor").value;
    const flavor = document.getElementById("filter-flavor").value;
    for (const tr of document.querySelectorAll("#catalog-table tbody tr")) {
      const minorOk = !minor || tr.dataset.minor === minor;
      const flavorOk = !flavor || tr.dataset.flavor === flavor;
      tr.hidden = !(minorOk && flavorOk);
    }
  }

  // ----------------------------------------------------- generator dropdown
  // Single image picker for the consolidated launch form. Each <option>
  // carries a data-flavor attribute so we can mark small options as
  // disabled when the form switches into single-file mode (the
  // jupyterlab-open-url-parameter extension only ships in xl).
  function populateGeneratorImages(images, latest) {
    const sel = document.getElementById("launch-image");
    if (!sel) return;
    const options = [
      { value: "latest-xl",    label: `latest-xl (=${latest}-xl)`,    flavor: "xl" },
      { value: "latest-small", label: `latest-small (=${latest}-small)`, flavor: "small" },
    ];
    for (const img of images) {
      options.push({ value: img.binder_tag, label: img.binder_tag, flavor: img.flavor });
    }
    for (const o of options) {
      const opt = document.createElement("option");
      opt.value = o.value;
      opt.textContent = o.label;
      opt.dataset.flavor = o.flavor;
      sel.appendChild(opt);
    }
    sel.value = "latest-xl";
  }

  // -------------------------------------------------- consolidated form
  // Single launch form. Detects mode from the URL the user enters:
  //   raw.githubusercontent.com → "file" mode (uses jupyterlab-open-
  //                                url-parameter ?fromURL=)
  //   github.com / anything else → "clone" mode (uses nbgitpuller
  //                                git-pull on the whole repo)
  // The user can override file→clone via the "Clone full repo instead?"
  // link that appears in file mode; we then derive the implicit
  // owner/repo/branch/path from the raw URL.
  //
  // overrideMode is null in the auto state and 'clone'|'file' when
  // the user has explicitly overridden the detection.
  let overrideMode = null;

  function wireGenerators() {
    const ids = ["launch-url", "launch-branch", "launch-path", "launch-image"];
    for (const id of ids) {
      const el = document.getElementById(id);
      el.addEventListener("input", refreshLaunch);
      el.addEventListener("change", refreshLaunch);
    }
    // Editing the URL clears any prior override (the user is starting
    // over with a fresh URL, so auto-detect should take over again).
    document.getElementById("launch-url").addEventListener("input", () => {
      overrideMode = null;
    });
    document.getElementById("launch-copy")
      .addEventListener("click", () => copyOutput("launch-out", "launch-copy", "launch-open"));
    document.getElementById("launch-badge-copy")
      .addEventListener("click", (e) =>
        copyToClipboard(document.getElementById("launch-badge-md").value, e.currentTarget));
    refreshLaunch();
  }

  // Detect what launch mode the current URL implies. Returns:
  //   { mode: "file",   raw }                                    raw .ipynb URL
  //   { mode: "clone",  repoUrl, branch?, path?, repoName }      github URL
  //   { mode: "invalid" }                                        unparseable
  function detectMode(input) {
    const raw = (input || "").trim();
    if (!raw) return { mode: "empty" };
    let u;
    try { u = new URL(raw); } catch { return { mode: "invalid" }; }
    if (u.hostname === "raw.githubusercontent.com") {
      // raw.githubusercontent.com/USER/REPO/BRANCH/path/file.ipynb
      const parts = u.pathname.split("/").filter(Boolean);
      const out = { mode: "file", raw };
      if (parts.length >= 3) {
        out.owner = parts[0];
        out.repo  = parts[1];
        out.branch = parts[2];
        out.path = parts.slice(3).join("/");
        out.repoName = parts[1];
      }
      return out;
    }
    if (u.hostname === "github.com") {
      const parts = u.pathname.replace(/\.git$/, "").split("/").filter(Boolean);
      if (parts.length < 2) return { mode: "invalid" };
      const repoName = parts[1];
      const out = { mode: "clone", repoUrl: `https://github.com/${parts[0]}/${parts[1]}`, repoName };
      if (parts.length >= 4 && (parts[2] === "blob" || parts[2] === "tree")) {
        out.branch = parts[3];
        out.path   = parts.slice(4).join("/");
      }
      return out;
    }
    return { mode: "invalid" };
  }

  // Apply a detection result to the form: split a /blob/ URL into its
  // pieces (matching the previous maybeSplitFullRepoUrl behaviour),
  // show/hide Branch + Path, set the mode note, and gate image
  // options to xl when in file mode.
  function applyDetection(det) {
    const urlField    = document.getElementById("launch-url");
    const branchField = document.getElementById("launch-branch");
    const pathField   = document.getElementById("launch-path");
    const cloneFields = document.getElementById("launch-clone-fields");
    const note        = document.getElementById("launch-mode-note");
    const imageSel    = document.getElementById("launch-image");

    const effectiveMode =
      overrideMode ||
      (det.mode === "file" || det.mode === "clone" ? det.mode : null);

    // Auto-split /blob/ URLs into clone fields. Only when we're in
    // clone mode AND the field has a /blob/ form; preserve user-typed
    // branch/path values if non-empty.
    if (effectiveMode === "clone" && det.mode === "clone" && det.branch) {
      urlField.value = det.repoUrl;
      if (!branchField.value.trim()) branchField.value = det.branch;
      if (!pathField.value.trim() && det.path) pathField.value = det.path;
    }

    // Show clone-only fields only in clone mode.
    cloneFields.hidden = effectiveMode !== "clone";

    // xl-only when in file mode.
    for (const opt of imageSel.options) {
      const disabled = effectiveMode === "file" && opt.dataset.flavor !== "xl";
      opt.disabled = disabled;
    }
    if (effectiveMode === "file" && imageSel.selectedOptions[0]?.disabled) {
      imageSel.value = "latest-xl";
    }

    // Symmetric mode note + toggle. The form has two launch shapes:
    //   - clone-the-whole-repo (nbgitpuller)
    //   - fetch a single .ipynb (jupyterlab-open-url-parameter)
    // We always show the user which one is active and offer the
    // other shape when it's applicable — i.e. in clone mode only if
    // there's a usable .ipynb path; in file mode always (we can
    // derive owner+repo+branch+path from the raw URL).
    note.hidden = false;
    note.innerHTML = ""; // clear any stale link listeners by removing the node
    if (effectiveMode === "file") {
      const span = document.createElement("span");
      span.textContent = "Single-notebook mode — fetches just this .ipynb. ";
      note.appendChild(span);
      if (det.owner && det.repo) {
        note.appendChild(makeOverrideLink("Clone full repo instead?", () => {
          // Synthesise a github.com URL so detectMode re-runs in clone mode.
          urlField.value = `https://github.com/${det.owner}/${det.repo}`;
          if (det.branch) branchField.value = det.branch;
          if (det.path)   pathField.value   = det.path;
          overrideMode = "clone";
          refreshLaunch();
        }));
      }
    } else if (effectiveMode === "clone") {
      const branchNow = branchField.value.trim();
      const pathNow   = pathField.value.trim();
      const canSingle =
        det.repoUrl &&
        pathNow.endsWith(".ipynb") &&
        branchNow.length > 0;
      const span = document.createElement("span");
      span.textContent = pathNow
        ? "Clone-repo mode — clones the whole repo and opens the file at launch. "
        : "Clone-repo mode — clones the whole repo on launch. ";
      note.appendChild(span);
      if (canSingle) {
        // Synthesise the raw.githubusercontent.com URL from the
        // pieces we have, so detectMode re-runs in file mode.
        // det.repoUrl is like https://github.com/OWNER/REPO; pull the
        // owner+repo back out for the raw URL.
        const m = det.repoUrl.match(/^https:\/\/github\.com\/([^/]+)\/([^/]+)/);
        if (m) {
          const owner = m[1], repo = m[2];
          note.appendChild(makeOverrideLink("Open just this notebook (no clone) instead?", () => {
            urlField.value = `https://raw.githubusercontent.com/${owner}/${repo}/${branchNow}/${pathNow}`;
            overrideMode = "file";
            refreshLaunch();
          }));
        }
      }
    } else {
      note.hidden = true;
    }

    return effectiveMode;
  }

  // Build a fresh inline override link (avoids accumulating listeners
  // since the parent <p>'s innerHTML is cleared on each render).
  function makeOverrideLink(text, onClick) {
    const a = document.createElement("a");
    a.href = "#";
    a.textContent = text;
    a.addEventListener("click", (e) => { e.preventDefault(); onClick(); });
    return a;
  }

  // Main render: read the current form, detect mode, apply, then
  // build the Binder URL + badge markdown for that mode.
  function refreshLaunch() {
    const det     = detectMode(document.getElementById("launch-url").value);
    const out     = document.getElementById("launch-out");
    const open    = document.getElementById("launch-open");
    const image   = document.getElementById("launch-image").value;

    if (det.mode === "empty") {
      out.value = "";
      open.hidden = true;
      clearLaunchBadge();
      document.getElementById("launch-clone-fields").hidden = true;
      document.getElementById("launch-mode-note").hidden = true;
      return;
    }
    if (det.mode === "invalid") {
      out.value = "(unrecognised URL — paste a github.com or raw.githubusercontent.com URL)";
      open.hidden = true;
      clearLaunchBadge();
      return;
    }

    const mode = applyDetection(det);

    let url, launchParams = new URLSearchParams();
    launchParams.set("image", image);
    if (mode === "file") {
      const raw = det.raw;
      const inner = `lab?fromURL=${encodeURIComponent(raw)}`;
      url = `https://mybinder.org/v2/gh/${REPO}/${image}?urlpath=${encodeURIComponent(inner)}`;
      launchParams.set("file", raw);
    } else { // clone
      // Read live values (applyDetection may have just populated them).
      const branch = document.getElementById("launch-branch").value.trim();
      const path   = document.getElementById("launch-path").value.trim();
      // Resolve the bare repo URL: prefer detection's repoUrl (handles
      // /blob/ etc.), otherwise use the field as-is.
      const repoUrl  = det.repoUrl || document.getElementById("launch-url").value.trim();
      const repoName = det.repoName || "repo";
      const innerParams = new URLSearchParams();
      innerParams.set("repo", repoUrl);
      if (branch) innerParams.set("branch", branch);
      innerParams.set("urlpath", path ? `lab/tree/${repoName}/${path}` : `lab/tree/${repoName}`);
      url = `https://mybinder.org/v2/gh/${REPO}/${image}?urlpath=${encodeURIComponent("git-pull?" + innerParams.toString())}`;
      launchParams.set("repo", repoUrl);
      if (branch) launchParams.set("branch", branch);
      if (path)   launchParams.set("path", path);
    }
    out.value = url;
    open.href = url;
    open.hidden = true;
    updateLaunchBadge(image, launchParams);
  }

  // The launch form always embeds a notebook (repo or single .ipynb),
  // so we use the "launch on QuBins" badge variant; same as before,
  // but with single-form IDs.
  function updateLaunchBadge(image, launchParams) {
    const md      = document.getElementById("launch-badge-md");
    const preview = document.getElementById("launch-badge-preview");
    const link    = document.getElementById("launch-badge-link");
    const badgeUrl  = `${PAGES}/badges/launch-on-qubins-${image}.svg`;
    const launchUrl = `${PAGES}/launch/?${launchParams.toString()}`;
    md.value = `[![launch on QuBins ${image}](${badgeUrl})](${launchUrl})`;
    preview.src = badgeUrl;
    preview.alt = `launch on QuBins ${image}`;
    link.href = launchUrl;
    link.hidden = false;
  }

  function clearLaunchBadge() {
    document.getElementById("launch-badge-md").value = "";
    const link = document.getElementById("launch-badge-link");
    link.removeAttribute("href");
    link.hidden = true;
    document.getElementById("launch-badge-preview").removeAttribute("src");
  }

  // ------------------------------------------------------------------ utils
  function copyToClipboard(text, btn) {
    navigator.clipboard.writeText(text).then(
      () => {
        const original = btn.textContent;
        btn.textContent = "Copied!";
        setTimeout(() => { btn.textContent = original; }, 1500);
      },
      () => {
        btn.textContent = "Copy failed";
      }
    );
  }

  function copyOutput(outId, btnId, openId) {
    const text = document.getElementById(outId).value;
    if (!text) return;
    copyToClipboard(text, document.getElementById(btnId));
    // Surface the open link only after explicit copy, matching the
    // "see the URL before launching" UX choice.
    document.getElementById(openId).hidden = false;
  }

})();
